import{_ as a,c as i,o as t,a1 as o}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse(`{"title":"FAQ et Optimisation : Dépannage, Commandes CLI, Réglage des Performances | Tutoriel Clawdbot","description":"Résolvez les problèmes courants lors de l'utilisation de Clawdbot, maîtrisez la référence complète des commandes CLI et apprenez les techniques d'optimisation des performances pour améliorer la stabilité du système et la vitesse de réponse.","frontmatter":{"title":"FAQ et Optimisation : Dépannage, Commandes CLI, Réglage des Performances | Tutoriel Clawdbot","sidebarTitle":"Que faire en cas de problème","subtitle":"FAQ et Optimisation","description":"Résolvez les problèmes courants lors de l'utilisation de Clawdbot, maîtrisez la référence complète des commandes CLI et apprenez les techniques d'optimisation des performances pour améliorer la stabilité du système et la vitesse de réponse.","tags":["FAQ","Dépannage","CLI","Optimisation des Performances"],"order":300},"headers":[],"relativePath":"fr/moltbot/moltbot/faq/index.md","filePath":"fr/moltbot/moltbot/faq/index.md"}`),s={name:"fr/moltbot/moltbot/faq/index.md"};function r(n,e,l,d,p,m){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="faq-et-optimisation" tabindex="-1">FAQ et Optimisation <a class="header-anchor" href="#faq-et-optimisation" aria-label="Permalink to &quot;FAQ et Optimisation&quot;">​</a></h1><p>Ce chapitre vous aide à résoudre divers problèmes lors de l&#39;utilisation de Clawdbot, à maîtriser les méthodes complètes d&#39;opération en ligne de commande et à apprendre comment optimiser les performances du système.</p><div class="info custom-block"><p class="custom-block-title">Recommandation sur l&#39;Ordre d&#39;Apprentissage</p><p>Il est recommandé de lire ce chapitre dans l&#39;ordre suivant :</p><ol><li>Apprenez d&#39;abord <strong><a href="./cli-commands/">Référence des Commandes CLI</a></strong> —— Maîtrisez les opérations de base et les outils de débogage</li><li>Ensuite apprenez <strong><a href="./troubleshooting/">Dépannage</a></strong> —— Pour identifier et résoudre rapidement les problèmes lorsqu&#39;ils surviennent</li><li>Enfin apprenez <strong><a href="./performance-optimization/">Optimisation des Performances</a></strong> —— Pour améliorer l&#39;efficacité du système</li></ol></div><h2 id="navigation-des-sous-pages" tabindex="-1">Navigation des Sous-pages <a class="header-anchor" href="#navigation-des-sous-pages" aria-label="Permalink to &quot;Navigation des Sous-pages&quot;">​</a></h2><h3 id="depannage" tabindex="-1"><a href="./troubleshooting/">Dépannage</a> <a class="header-anchor" href="#depannage" aria-label="Permalink to &quot;[Dépannage](./troubleshooting/)&quot;">​</a></h3><p>Un guide complet de dépannage pour les problèmes courants, couvrant :</p><ul><li>Échecs de démarrage de Gateway</li><li>Problèmes de connexion de canaux (WhatsApp, Telegram, Slack, etc.)</li><li>Erreurs d&#39;authentification et problèmes d&#39;autorisation</li><li>Échecs d&#39;invocation d&#39;outils</li><li>Exceptions de gestion de sessions</li></ul><p><strong>Quand utiliser</strong> : Lorsque vous rencontrez des problèmes spécifiques et devez les dépanner et les résoudre rapidement.</p><hr><h3 id="reference-des-commandes-cli" tabindex="-1"><a href="./cli-commands/">Référence des Commandes CLI</a> <a class="header-anchor" href="#reference-des-commandes-cli" aria-label="Permalink to &quot;[Référence des Commandes CLI](./cli-commands/)&quot;">​</a></h3><p>Liste complète des commandes et instructions d&#39;utilisation, incluant :</p><ul><li>Commandes de contrôle Gateway (démarrage, redémarrage, état)</li><li>Commandes d&#39;interaction Agent</li><li>Gestion et configuration de modèles</li><li>Gestion de canaux (connexion, état, déconnexion)</li><li>Gestion de sessions (liste, réinitialisation, suppression, compression)</li><li>Gestion de nœuds (liste, invocation, appariement)</li><li>Gestion de compétences et assistant de configuration</li></ul><p><strong>Quand utiliser</strong> : Lorsque vous avez besoin de trouver rapidement l&#39;utilisation et les paramètres d&#39;une commande, ou d&#39;apprendre la fonctionnalité complète de CLI.</p><hr><h3 id="optimisation-des-performances" tabindex="-1"><a href="./performance-optimization/">Optimisation des Performances</a> <a class="header-anchor" href="#optimisation-des-performances" aria-label="Permalink to &quot;[Optimisation des Performances](./performance-optimization/)&quot;">​</a></h3><p>Techniques d&#39;optimisation pour améliorer les performances et la vitesse de réponse de Gateway, couvrant :</p><ul><li>Mise en cache des Prompts (Prompt Caching) pour réduire les coûts</li><li>Élagage de Sessions (Session Pruning) pour réduire le contexte</li><li>Contrôle de concurrence et gestion des ressources</li><li>Optimisation de la mémoire et garbage collection</li><li>Réglage des niveaux de journalisation</li></ul><p><strong>Quand utiliser</strong> : Lorsque le système fonctionne lentement, l&#39;utilisation des ressources est élevée, ou vous souhaitez améliorer l&#39;expérience utilisateur.</p><h2 id="conditions-prealables" tabindex="-1">Conditions Préalables <a class="header-anchor" href="#conditions-prealables" aria-label="Permalink to &quot;Conditions Préalables&quot;">​</a></h2><p>Avant d&#39;apprendre ce chapitre, il est recommandé d&#39;avoir complété :</p><ul><li>✅ <strong><a href="./../../start/getting-started/">Démarrage Rapide</a></strong> —— Comprendre les processus de base d&#39;installation et de configuration</li><li>✅ <strong><a href="./../../start/gateway-startup/">Démarrer Gateway</a></strong> —— Savoir comment démarrer et gérer Gateway</li></ul><h2 id="prochaines-etapes" tabindex="-1">Prochaines Étapes <a class="header-anchor" href="#prochaines-etapes" aria-label="Permalink to &quot;Prochaines Étapes&quot;">​</a></h2><p>Après avoir terminé ce chapitre, vous pouvez continuer à apprendre :</p><ul><li><strong><a href="./../../appendix/config-reference/">Référence Complète de Configuration</a></strong> —— Comprendre en profondeur les explications détaillées de toutes les options de configuration</li><li><strong><a href="./../../appendix/deployment/">Options de Déploiement</a></strong> —— Apprendre comment déployer Clawdbot sur différentes plateformes</li><li><strong><a href="./../../appendix/development/">Guide de Développement</a></strong> —— Comprendre le développement de plugins et le processus de contribution</li></ul>',24)])])}const g=a(s,[["render",r]]);export{u as __pageData,g as default};
